#!/usr/bin/env python3
"""
QuantLab Migration Script
Run this from the root of your quantlab-project repository:
    python migrate_v2.py

It will:
  1. Create the new directory structure
  2. Write every new file
  3. Remove flat scripts that are now replaced
  4. Run the test suite to confirm 29/29 pass
"""
import base64, os, subprocess, sys
from pathlib import Path

FILES = {
    'src/quantlab/__init__.py': '',
    'src/quantlab/providers/__init__.py': '',
    'src/quantlab/providers/base.py': '',
    'src/quantlab/providers/ibkr.py': '',
    'src/quantlab/providers/providers.py': '',
    'src/quantlab/news/__init__.py': '',
    'src/quantlab/signals/__init__.py': '',
    'src/quantlab/research/__init__.py': '',
    'src/quantlab/storage/__init__.py': '',
    'src/quantlab/risk/__init__.py': '',
    'src/quantlab/execution/__init__.py': '',
    'src/quantlab/utils/__init__.py': '',
    'scripts/scan_universe.py': '',
    'scripts/run_backtest.py': '',
    'tests/test_quantlab.py': '',
    'tests/__init__.py': '',
    'pyproject.toml': '',
    '.gitignore': '',
    'README.md': '',
    'WSL2_SETUP.sh': '',
}

REMOVE_OLD = [
    # Flat scripts replaced by src/quantlab/ modules + scripts/
    "fetch_bars.py",
    "run_backtest.py",
    "run_http_provider.py",
    "run_mock_provider.py",
    "run_signal.py",
    "smoke_test.py",
    "verify_env.py",
    # Keep: fetch_ibkr_news.py, fetch_ibkr_option_chain.py,
    # fetch_ibkr_option_quotes.py, tag_ibkr_news.py,
    # run_backtest_with_news.py, test_ibkr_connection.py,
    # test_ibkr_history.py  (move to scripts/ below)
]

MOVE_TO_SCRIPTS = [
    "fetch_ibkr_news.py",
    "fetch_ibkr_option_chain.py",
    "fetch_ibkr_option_quotes.py",
    "tag_ibkr_news.py",
    "run_backtest_with_news.py",
    "test_ibkr_connection.py",
    "test_ibkr_history.py",
]

def main():
    root = Path.cwd()
    if not (root / 'pyproject.toml').exists():
        print('ERROR: Run this from the quantlab-project root directory.')
        print(f'Current directory: {root}')
        sys.exit(1)

    print('=== QuantLab v0.2 Migration ===')
    print(f'Project root: {root}')
    print()

    # 1. Create directory structure
    dirs = [
        'src/quantlab/providers',
        'src/quantlab/news',
        'src/quantlab/options',
        'src/quantlab/signals',
        'src/quantlab/research',
        'src/quantlab/storage',
        'src/quantlab/risk',
        'src/quantlab/execution',
        'src/quantlab/utils',
        'scripts',
        'tests',
        'notebooks',
        'data/raw',
        'data/processed',
        'data/external',
        'output',
    ]
    for d in dirs:
        (root / d).mkdir(parents=True, exist_ok=True)
    print(f'[1/5] Created {len(dirs)} directories')

    # 2. Write all new files
    written = 0
    for dest, encoded in FILES.items():
        path = root / dest
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_bytes(base64.b64decode(encoded))
        written += 1
    print(f'[2/5] Wrote {written} files')

    # 3. Move old scripts to scripts/
    moved = 0
    for fname in MOVE_TO_SCRIPTS:
        src = root / fname
        dst = root / 'scripts' / fname
        if src.exists() and not dst.exists():
            src.rename(dst)
            moved += 1
        elif src.exists() and dst.exists():
            src.unlink()  # already have it in scripts/
            moved += 1
    print(f'[3/5] Moved {moved} scripts to scripts/')

    # 4. Remove replaced flat scripts
    removed = 0
    for fname in REMOVE_OLD:
        f = root / fname
        if f.exists():
            f.unlink()
            removed += 1
    print(f'[4/5] Removed {removed} replaced flat scripts')

    # 5. Rename _gitignore to .gitignore if needed
    old_gi = root / '_gitignore'
    new_gi = root / '.gitignore'
    if old_gi.exists():
        if new_gi.exists():
            old_gi.unlink()
        else:
            old_gi.rename(new_gi)
        print('[4.5] Renamed _gitignore to .gitignore')

    # 5. Run tests
    print('[5/5] Running test suite...')
    env = os.environ.copy()
    env['PYTHONPATH'] = str(root / 'src')
    result = subprocess.run(
        [sys.executable, '-m', 'pytest', 'tests/test_quantlab.py', '-v', '--tb=short'],
        cwd=root, env=env, capture_output=False
    )
    print()
    if result.returncode == 0:
        print('=== Migration complete. All tests passed. ===')
        print()
        print('Next steps:')
        print('  1. pip install -e ".[dev]"')
        print('  2. git add -A')
        print('  3. git commit -m "Restructure to 7-layer architecture v0.2"')
        print('  4. git push')
        print('  5. Follow WSL2_SETUP.sh to set up WSL2')
    else:
        print('=== Tests failed — check output above. ===')
        sys.exit(1)

if __name__ == '__main__':
    main()